+function getRunGroupKey(run) {
+  const m = run.manifest || {};
+  switch (currentGroupBy) {
+    case 'model':
+      return m.model ? m.model.split('/').pop() : 'unknown';
+    case 'adapter':
+      return (m.adapter || 'unknown').replace(/_agent$/, '').replace(/:.*$/, '');
+    case 'date':
+      return m.started_at ? m.started_at.slice(0, 10) : 'unknown';
+    default:
+      return null;
+  }
+}
+
+function sortRunsForGroup(runList) {
+  if (!currentGroupBy) {
+    // Default sort: active first, then by total tasks descending, then by name
+    runList.sort((a, b) => (b.active ? 1 : 0) - (a.active ? 1 : 0)
+      || ((b.summary?.total || 0) - (a.summary?.total || 0))
+      || a.job_name.localeCompare(b.job_name));
+    return;
+  }
+  // Sort by group key, then within group by total tasks descending
+  runList.sort((a, b) => {
+    const ga = getRunGroupKey(a);
+    const gb = getRunGroupKey(b);
+    if (ga !== gb) {
+      if (ga === 'unknown') return 1;
+      if (gb === 'unknown') return -1;
+      if (currentGroupBy === 'date') return gb.localeCompare(ga); // newest first
+      return ga.localeCompare(gb);
+    }
+    return (b.summary?.total || 0) - (a.summary?.total || 0)
+      || a.job_name.localeCompare(b.job_name);
+  });
+}
+
+function buildRunOption(run) {
+  const opt = document.createElement('option');
+  opt.value = run.job_name;
+  const status = run.active ? '' : ' (archived)';
+  const summary = run.summary ? ` [${run.summary.pass}/${run.summary.total}]` : '';
+  opt.textContent = run.job_name + summary + status;
+  return opt;
+}
